def execute(ctx):
    retirement = ctx.input

    # Debit from inventory
    position_keeping.initiate_log(
        account_id=retirement.inventory_account,
        amount=retirement.quantity,
        instrument_code=retirement.credit_type,
        direction="DEBIT",
        attributes={
            "vintage_year": retirement.vintage_year,
            "project_id": retirement.project_id,
        },
    )

    # Credit to retirement account (permanent, non-reversible)
    position_keeping.initiate_log(
        account_id=retirement.retirement_account,
        amount=retirement.quantity,
        instrument_code=retirement.credit_type,
        direction="CREDIT",
        attributes={
            "vintage_year": retirement.vintage_year,
            "retirement_reason": retirement.reason,
        },
    )

    return {"status": "retired", "retirement_id": retirement.retirement_id}
